import { findTreeNode, insertTreeNode, updateTreeNode, flattenTree } from 'std-kit';

const tree = {
  id: 'root',
  children: [
    { id: 'a', label: 'Alpha' },
    { id: 'b', label: 'Beta', children: [{ id: 'b1', label: 'Beta 1' }] },
  ],
};

